import React, { useState } from 'react';
import { NavLink, useLocation } from 'react-router-dom';
import PropTypes from 'prop-types';
import classNames from 'classnames';
import './Header.scss';
import { Categories } from '../Categories';

export const Header = ({ query, setQuery, appliedQuery, setAppliedQuery }) => {
  const [menu, setMenu] = useState(true);
  // const [query, setQuery] = useState('');
  // const [appliedQuery, setAppliedQuery] = useState('');
  // const [value, setValue] = useState('');
  // const [categories, setCategories] = useState(false);
  const location = useLocation();
  // console.log(location);
  // const {pathname}
  const [path, setPath] = useState('/home');
  console.log(query);
  // const location = useLocation();
  // const searchParams = new URLSearchParams(location.search);
  // const applyiedQuery = searchParams.get('query') || '';
  // const match = useRouteMatch();

  return (
    <header className="Header">
      <div className="container-headerNav">
        <form className="Header-Form form">
          <button
            type="button"
            className="button-search"
            onClick={() => setQuery('')}
          />
          <input
            type="text"
            className="form-input"
            value={query}
            onChange={e => setQuery(e.target.value)}
            placeholder="Search..."
          />
          {query && (
            <button
              type="button"
              className="button-clear"
              onClick={() => setQuery('')}
            >
              {}
            </button>
          )}
        </form>
        <div className="container-nav">
          <nav className="Header-Nav Nav">
            <NavLink
              to="/home"
              className="Nav-Link"
              onClick={() => setPath('/home')}
            >
              Home
            </NavLink>
            <NavLink
              to="/articles"
              className="Nav-Link"
              onClick={() => setPath('/articles')}
            >
              Articles
            </NavLink>
          </nav>
          <div className="container-links">
            <a href="http://insagram.com" className="Header-Instagram link">{}</a>
            <a href="http://twitter.com" className="Header-Twitter link">{}</a>
            <a href="http://linkedin.com" className="Header-LinkedIn link">{}</a>
          </div>
        </div>
      </div>
      <div className={classNames('container', {
        container_menu: menu,
      })}
      >
        <div className="Header-Logo">News App</div>
        <div className="Header-Menu Menu">
          <ul className={classNames('Menu-List', {
            menu_visible: !menu,
          })}
          >
            <li className="Menu-Item">
              <div className="container-category">
                <NavLink
                  to={`${path}/categories`}
                  className="Menu-Link"
                  onClick={() => <Categories />}
                >
                  Categories
                </NavLink>
                {location.pathname.includes('categories') && <Categories />}
              </div>
            </li>
            <li className="Menu-Item">
              <NavLink to={`${path}/trending`} className="Menu-Link">
              Trending news{/* &#9889; Trending news */}
              </NavLink>
            </li>
          </ul>
          <button
            type="button"
            className={classNames('button-menu', {
              menu_open: menu,
              menu_cross: !menu,
            })}
            onClick={() => setMenu(!menu)}
          />
        </div>
      </div>
    </header>
  );
};

Header.propTypes = {
  query: PropTypes.string.isRequired,
  setQuery: PropTypes.func.isRequired,
  appliedQuery:
  setA
}
